async (params, browser) => {
  // Search Facebook Marketplace
  await browser.open(`https://www.facebook.com/marketplace/search/?query=${params.query}`)

  // Wait for Marketplace results
  await browser.waitForSelector('[role=\'main\'], a[href*=\'/marketplace/item/\']', 15000)

  // Let listings render
  await browser.wait(3000)

  // Scroll to load more listings
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract Marketplace listings
  const marketplace_results = await browser.evaluate(`const results = []; const itemLinks = document.querySelectorAll('a[href*="/marketplace/item/"]'); const seen = new Set(); for (let i = 0; i < itemLinks.length && results.length < 15; i++) { const link = itemLinks[i]; const href = link.getAttribute('href') || ''; const itemId = href.match(/\/marketplace\/item\/(\d+)/); if (itemId && seen.has(itemId[1])) continue; if (itemId) seen.add(itemId[1]); const container = link.closest('div') || link; const spans = container.querySelectorAll('span'); let title = ''; let price = ''; let location = ''; for (const span of spans) { const text = span.textContent.trim(); if (!price && (text.startsWith('$') || text.startsWith('Free') || /^[\d,.]+\s*(USD|EUR|GBP|\$)/.test(text) || text === 'Free')) { price = text; } else if (!title && text.length > 5 && text.length < 200 && !text.startsWith('$')) { title = text; } else if (!location && text.length > 2 && text.length < 100 && text !== title && !text.startsWith('$') && title) { location = text; } } const imgEl = container.querySelector('img'); const image = imgEl ? imgEl.getAttribute('src') || '' : ''; const fullUrl = href.startsWith('http') ? href : 'https://www.facebook.com' + href; if (title || price) { results.push({ title: title, price: price, location: location, image: image, url: fullUrl }); } } return { query: params.query, result_count: results.length, results: results }`)

  return marketplace_results
}
